{"file_text": "@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
        <a href="courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <p>Fill out the form below to request enrollment in a course.</p>

    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" method="post">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
            <ValidationMessage For="() => Model.StudentName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
            <ValidationMessage For="() => Model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                <option value="0">-- Select a Course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.CourseCode — @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private IReadOnlyList<Course> courses = [];
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(Model.CourseId);
        selectedCourseTitle = course?.Title ?? "Unknown Course";
        CatalogService.SubmitEnrollmentRequest(Model);
        submitted = true;
    }
}
